func take_damage(amount):
    current_health -= amount
    emit_signal("health_changed", amount) # Tell UI/Manager without direct reference

**Example:**
```typescript
interface Duck {
  quack(): void;
  swim(): void;
}

function makeDuckQuack(duck: Duck) {
  duck.quack();
}

class RealDuck {
  quack() { console.log("Quack!"); }
  swim() { console.log("Swimming..."); }
}

class Robot {
  quack() { console.log("Beep quack!"); }
  swim() { console.log("Underwater mode!"); }
}

#### ✅ Accepting Flexible Objects
```typescript
interface Logger {
  log(message: string): void;
}

function processWithLogger(obj: Logger) {
  obj.log("Processing...");
}

const consoleLogger: Logger = console;
const customLogger = {
  log: (msg: string) => console.log(`[${msg}]`)
};

processWithLogger(consoleLogger);
processWithLogger(customLogger); // ✅
```

#### ✅ Function Parameters
```typescript
function greet(obj: { name: string; greeting: string }) {
  return `${obj.greeting}, ${obj.name}!`;
}

#### ✅ Accepting Extra Properties (Excess Property Checking)
```typescript
interface User {
  id: number;
  name: string;
}

```typescript
function process(obj: unknown) {
  if (typeof obj === 'object' && obj !== null && 'quack' in obj) {
    const duck = obj as { quack: () => void };
    duck.quack();
  }
}
```

```typescript
interface Cat {
  type: 'cat';
  meow(): void;
}

interface Dog {
  type: 'dog';
  bark(): void;
}

function makeSound(animal: Animal) {
  if (animal.type === 'cat') {
    animal.meow();
  } else {
    animal.bark();
  }
}
```

**1. A System for Decentralized Issuance of Community Tax Certificates and Government Permits, comprising:**
a. A **Decentralized Identity Wallet Module** executable on a user device, configured to generate a Decentralized Identifier (DID) and store cryptographic keys;
b. An **Issuing Authority Node**, configured to authenticate user eligibility and digitally sign credentials;
c. A **Permissioned Blockchain Network**, configured to immutably record transaction hashes and smart contracts related to the issuance;
d. A **Machine Learning Risk Engine**, communicatively coupled to the Issuing Authority Node and configured to analyze pre-issuance transaction data to generate a dynamic risk score; and
e. A **Smart Contract Module**, configured to automate payment processing and trigger credential minting only upon a risk score indicating a probability of fraud below a predetermined threshold;
wherein the issuance of a Community Tax Certificate (CTC) is contingent upon the successful validation of the dynamic risk score by the Machine Learning Risk Engine prior to the cryptographic signing of the credential.

**6. A Computer-Implemented Method for the Issuance of Digital Government Permits, comprising the steps of:**
(a) Receiving a digital permit application request from a User Device;
(b) Extracting device metadata, location data, and behavioral biometric data from said request;
(c) Processing said data through a pre-trained Machine Learning Risk Model to calculate a Trust Score;
(d) Comparing the Trust Score against a risk threshold;
(e) In the event the Trust Score exceeds a safe limit, initiating a cryptographic challenge-response authentication protocol;
(f) In the event the Trust Score is within the safe limit, executing a Smart Contract on a Blockchain Network to accept a tax or permit payment fee;
(g) Upon payment confirmation, invoking an Issuing Authority Signing Key to generate a cryptographic signature for the Digital Permit; and
(h) Minting a Non-Transferable Verifiable Credential containing the permit data to the User Device's Digital Wallet.

    INDEX idx_execution_status (status),
    INDEX idx_execution_date (started_at),
    INDEX idx_execution_test_id (test_id)
);
